INSERT INTO questions
  (id, specialty, stem, choices, correct_answer, explanation, telemetry, domain_name, subtopic, difficulty, "references", status, category)
VALUES
('authored-batch-r20-019', 'Pediatric', 'A 4-year-old, 16-kg boy returns to the emergency department 6 hours after outpatient adenotonsillectomy with active oral bleeding and several episodes of swallowing and spitting up dark blood. He last ate a popsicle 90 minutes ago. He is pale and anxious; heart rate 158/min, blood pressure 84/52 mmHg, SpO2 97% on room air, and capillary refill is 3 seconds. Two attempts at peripheral IV access have failed. The surgeon wants to return to the operating room emergently for control of the bleeding tonsillar fossa. After establishing IV access and giving a 20 mL/kg balanced crystalloid bolus, which induction and airway strategy is most appropriate?', '[{"text":"Inhalational induction with sevoflurane, maintain spontaneous ventilation, and intubate deep without neuromuscular blockade","label":"A","correct":false,"rationale":"A slow inhalational induction in a hypovolemic, full-stomach patient invites aspiration of swallowed blood and profound hypotension, making it the least safe approach."},{"text":"Awake fiberoptic intubation after topicalization to avoid hemodynamic instability","label":"B","correct":false,"rationale":"Awake fiberoptic intubation is impractical in a frightened 4-year-old and the fiberoptic view is rapidly obscured by active bleeding, so it is not appropriate here."},{"text":"Standard-dose propofol induction with rocuronium and routine laryngoscopy, deferring gastric decompression until after intubation","label":"C","correct":false,"rationale":"A full induction dose of propofol can precipitate severe hypotension in a hypovolemic child, and routine (non-rapid-sequence) laryngoscopy ignores the aspiration risk."},{"text":"Rapid sequence induction with a reduced dose of induction agent plus succinylcholine, suction immediately available, and a styletted tube one size smaller than usual","label":"D","correct":true,"rationale":"Correct: the bleeding tonsil patient is treated as a full stomach with a likely difficult, blood-obscured view, so RSI with a reduced induction dose (to limit hypotension), rapid-onset paralysis, ready suction, and a smaller styletted tube is the standard of care."},{"text":"Ketamine sedation with a nasopharyngeal airway and spontaneous ventilation while the surgeon cauterizes","label":"E","correct":false,"rationale":"Sedation without a secured airway leaves the trachea unprotected against ongoing blood aspiration and is unacceptable for an actively bleeding tonsil."}]'::jsonb, 'D', 'A post-tonsillectomy hemorrhage is a true anesthetic emergency: the child is hypovolemic and anemic from both visible and swallowed blood, has a stomach full of blood regardless of NPO status, and presents an airway whose view is obscured by ongoing bleeding. Resuscitate with isotonic fluid (and blood as needed) first, then perform a rapid sequence induction with a reduced dose of induction agent to limit hemodynamic collapse, succinylcholine or rocuronium for rapid paralysis, two working suctions, and a styletted endotracheal tube a half-to-full size smaller than predicted. Avoid the temptation of a slow spontaneous-ventilation inhalational induction, which prolongs the period of an unprotected airway in a full-stomach patient.', '{}'::jsonb, 'Subspecialty Care', 'Post-tonsillectomy hemorrhage — emergency airway and resuscitation', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/posttonsillectomy-hemorrhage/","source":"Posttonsillectomy Hemorrhage — OpenAnesthesia"}]'::jsonb, 'sme_review', 'Pediatric'),
('authored-batch-r20-020', 'Pediatric', 'A 3-month-old boy presents for elective bilateral inguinal hernia repair at a hospital-based surgical unit. He was born at 30 weeks gestation and is now 43 weeks postconceptual age. He was discharged from the NICU 3 weeks ago, takes no medications, and his mother reports no recent apnea spells at home. Preoperative hematocrit is 27%. The surgeon and anesthesia team are deciding between general endotracheal anesthesia and a spinal anesthetic. Which statement most accurately guides perioperative planning for this infant?', '[{"text":"Because he is asymptomatic at home, the case can proceed as a routine outpatient discharge after standard PACU recovery","label":"A","correct":false,"rationale":"His young postconceptual age plus anemia place him at meaningful risk for postoperative apnea, so same-day discharge is unsafe regardless of how well he appears at home."},{"text":"A pure spinal anesthetic supplemented with intravenous midazolam sedation eliminates the risk of postoperative apnea","label":"B","correct":false,"rationale":"Adding any sedative such as midazolam to a spinal abolishes the apnea-sparing advantage of regional technique, so this combination does not eliminate the risk."},{"text":"His apnea risk is negligible because he is already past 40 weeks postconceptual age","label":"C","correct":false,"rationale":"The risk does not fall below roughly 1% until about 54-56 weeks PCA, so 43 weeks PCA is still well within the high-risk window."},{"text":"Correcting his anemia is unnecessary because hematocrit has no relationship to apnea in former preterm infants","label":"D","correct":false,"rationale":"Anemia, particularly a hematocrit below 30%, is a well-established independent risk factor for postoperative apnea and warrants attention."},{"text":"He should be admitted for at least 12 hours of postoperative apnea and cardiorespiratory monitoring, and his hematocrit of 27% independently raises that risk","label":"E","correct":true,"rationale":"Correct: at 43 weeks PCA he is below the threshold where apnea risk becomes negligible, anemia (Hct <30%) is an independent risk factor, and current guidance is continuous monitoring for at least 12 hours postoperatively."}]'::jsonb, 'E', 'Former preterm infants are at risk for postoperative apnea, and risk is driven chiefly by low postconceptual age and anemia. The probability of apnea does not fall below about 5% until roughly 48-50 weeks PCA and below 1% until about 54-56 weeks PCA; a hematocrit under 30% is an independent risk factor. A pure spinal anesthetic can reduce apnea risk only if no sedatives or opioids are added — supplementing with midazolam or ketamine eliminates that benefit. Any at-risk infant should be admitted for continuous cardiorespiratory and apnea monitoring for at least 12 hours postoperatively rather than discharged the same day.', '{}'::jsonb, 'Subspecialty Care', 'Apnea of prematurity / postoperative apnea risk in the ex-premature infant', 'medium', '[{"url":"https://www.openanesthesia.org/postoperative_apnea_post_conceptual_age/","source":"Apnea of Prematurity and Postoperative Apnea — OpenAnesthesia"}]'::jsonb, 'sme_review', 'Pediatric'),
('authored-batch-r20-021', 'Pediatric', 'A healthy 5-year-old, 20-kg girl is undergoing examination under anesthesia via a natural-airway sevoflurane technique with a peripheral IV in place. As the surgeon manipulates the airway, she develops inspiratory stridor that progresses to complete absence of breath sounds, paradoxical chest-abdominal movement, and an SpO2 that falls from 99% to 84%. There is no capnograph trace and the bag does not move with attempted positive-pressure ventilation. You stop the stimulus and apply 100% oxygen with continuous positive airway pressure and a vigorous jaw thrust, but the obstruction persists and SpO2 continues to fall to 78%. What is the most appropriate next step?', '[{"text":"Deepen anesthesia with a bolus of intravenous propofol (about 0.5-1 mg/kg) and, if the spasm persists, give intravenous succinylcholine","label":"A","correct":true,"rationale":"Correct: when CPAP and jaw thrust fail, deepening with a small propofol bolus relaxes the cords in many cases, and succinylcholine is the definitive treatment for laryngospasm that does not break."},{"text":"Administer intravenous atropine 0.02 mg/kg and continue CPAP while waiting for the spasm to break","label":"B","correct":false,"rationale":"Atropine treats reflex bradycardia but does nothing to relieve the glottic closure itself, so it is not the next step for persistent desaturating laryngospasm."},{"text":"Immediately attempt direct laryngoscopy and intubation without any additional medication","label":"C","correct":false,"rationale":"Forcing a laryngoscope past tightly adducted cords in a light, spasming child can worsen the spasm and cause airway trauma, so pharmacologic treatment should come first."},{"text":"Perform an emergency surgical cricothyrotomy","label":"D","correct":false,"rationale":"A surgical airway is a last resort for a true ''cannot intubate, cannot oxygenate'' situation and is premature before succinylcholine has been given for reversible laryngospasm."},{"text":"Switch to ketamine to maintain spontaneous ventilation and lighten the anesthetic","label":"E","correct":false,"rationale":"Lightening the plane during active laryngospasm tends to worsen, not relieve, the reflex glottic closure."}]'::jsonb, 'A', 'Laryngospasm is an exaggerated, sustained glottic closure reflex that can rapidly cause hypoxia, bradycardia, and arrest in children. First-line management is to remove the stimulus, apply 100% oxygen with CPAP, and perform a firm jaw thrust (including pressure at the ''laryngospasm notch''). When these maneuvers fail and the child is desaturating, deepen anesthesia with a small propofol bolus; if the spasm still does not break, give succinylcholine (about 0.5-2 mg/kg IV, or roughly 4 mg/kg IM with atropine if no IV access) as the definitive treatment, with atropine for accompanying bradycardia.', '{}'::jsonb, 'Subspecialty Care', 'Pediatric laryngospasm — recognition and stepwise treatment', 'medium', '[{"url":"https://www.openanesthesia.org/keywords/laryngospasm/","source":"Laryngospasm — OpenAnesthesia"}]'::jsonb, 'sme_review', 'Pediatric'),
('authored-batch-r20-022', 'Principles & Preop', 'A 71-year-old man is scheduled for elective open repair of a 5.8-cm infrarenal abdominal aortic aneurysm. He has hypertension controlled on lisinopril, type 2 diabetes on metformin, and former 30-pack-year tobacco use, now quit. He had a drug-eluting coronary stent placed 4 years ago and has had no angina since; he is maintained on aspirin. He reports that he stopped exercising ''because of my knees'' and becomes short of breath after climbing one flight of stairs but cannot say whether he could climb two. His resting ECG shows old Q waves in the inferior leads. Vitals and basic labs are unremarkable. According to current ACC/AHA perioperative guidance, which single feature of this patient most strongly justifies obtaining further cardiac testing (e.g., pharmacologic stress imaging) before proceeding?', '[{"text":"His coronary stent was placed 4 years ago, which mandates stress testing before any noncardiac surgery","label":"A","correct":false,"rationale":"Incorrect: a remote, asymptomatic stent does not by itself mandate stress testing; its timing matters for antiplatelet decisions, not as an automatic indication for ischemia testing."},{"text":"His estimated functional capacity is less than 4 METs and cannot be reliably established in the setting of an elevated-risk vascular procedure","label":"B","correct":true,"rationale":"Correct: inability to achieve 4 METs (cannot climb two flights / walk up a hill) combined with an elevated-risk surgery is the guideline trigger for considering further testing when it would change management."},{"text":"His well-controlled hypertension on lisinopril independently elevates his risk enough to warrant imaging","label":"C","correct":false,"rationale":"Incorrect: well-controlled hypertension is a minor clinical factor and does not on its own justify further cardiac testing."},{"text":"The inferior Q waves on resting ECG confirm active ischemia requiring testing","label":"D","correct":false,"rationale":"Incorrect: old Q waves indicate a prior infarct, not active ischemia, and a resting ECG abnormality alone is not the decisive indication for stress imaging."},{"text":"His former tobacco use places him in a category that always requires preoperative cardiac stress testing","label":"E","correct":false,"rationale":"Incorrect: a remote smoking history is a risk factor but does not categorically mandate cardiac stress testing before surgery."}]'::jsonb, 'B', 'ACC/AHA perioperative algorithms use functional capacity as a pivotal branch point: a patient who can reliably achieve 4 or more METs generally proceeds without further cardiac testing regardless of an elevated-risk procedure, whereas one with poor (<4 METs) or indeterminate capacity facing elevated-risk surgery is the patient in whom stress testing may be considered if the result would change management. This man''s inability to climb two flights of stairs, coupled with an inability to estimate higher exertion, makes his functional capacity the most actionable risk feature. His remote stent and prior MI raise his baseline risk (and make him ASA III) but are not, by themselves, the trigger for additional ischemia testing.', '{}'::jsonb, 'Subspecialty Care', 'Functional capacity (METs) in preoperative cardiac risk assessment', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/preoperative-cardiac-risk-stratification-and-evaluation/","source":"Preoperative Cardiac Risk Stratification and Evaluation - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Principles & Preop'),
('authored-batch-r20-023', 'Principles & Preop', 'During a preoperative airway assessment for an elective thyroidectomy, a 54-year-old woman is asked to sit upright, open her mouth maximally, and protrude her tongue without phonating. The examiner can visualize the soft palate, the fauces, and the uvula, but the faucial (tonsillar) pillars are hidden behind the tongue. Her thyromental distance is 7 cm, mouth opening is 4 cm, and neck extension is full. Which modified Mallampati class does this oropharyngeal view represent, and what is its correct interpretation?', '[{"text":"Class III, indicating a potentially difficult laryngoscopy that mandates an awake fiberoptic approach","label":"A","correct":false,"rationale":"Incorrect: Class III is when only the soft palate and base of the uvula are seen, and no single class mandates a specific airway technique on its own."},{"text":"Class I, which by itself reliably rules out difficult intubation","label":"B","correct":false,"rationale":"Incorrect: Class I additionally shows the faucial pillars, and even a Class I view does not by itself rule out a difficult airway."},{"text":"Class II, generally reassuring, though no single test reliably excludes a difficult airway","label":"C","correct":true,"rationale":"Correct: visibility of the soft palate, fauces, and uvula with the faucial pillars hidden defines modified Mallampati Class II, a generally favorable view that must still be combined with other predictors."},{"text":"Class IV, which by itself confirms a difficult airway regardless of other findings","label":"D","correct":false,"rationale":"Incorrect: Class IV is when only the hard palate is visible, and no single class confirms a difficult airway in isolation."},{"text":"The classification is invalid because the patient should have been asked to phonate during the examination","label":"E","correct":false,"rationale":"Incorrect: the modified Mallampati test is performed without phonation, so the examination as described is valid."}]'::jsonb, 'C', 'In the modified Mallampati classification (assessed seated, mouth maximally open, tongue protruded, without phonation): Class I sees the soft palate, fauces, uvula, and pillars; Class II sees the soft palate, fauces, and uvula; Class III sees the soft palate and only the base of the uvula; and Class IV sees only the hard palate. Visualizing the soft palate, fauces, and uvula while the faucial pillars are hidden is the classic Class II view. Importantly, the Mallampati score has modest sensitivity and specificity, so it should be integrated with thyromental distance, mouth opening, neck mobility, and the 3-3-2 rule rather than used in isolation.', '{}'::jsonb, 'Subspecialty Care', 'Airway assessment and difficult-airway prediction', 'easy', '[{"url":"https://www.ncbi.nlm.nih.gov/books/NBK585119/","source":"Mallampati Score - StatPearls - NCBI Bookshelf"}]'::jsonb, 'sme_review', 'Principles & Preop'),
('authored-batch-r20-024', 'Neuro', 'A 54-year-old man undergoes a suboccipital craniotomy in the sitting position for resection of a vestibular schwannoma. He is monitored with a precordial Doppler over the right parasternal border, an arterial line, and capnography. Roughly 90 minutes into the dissection, the anesthetist hears a sudden change in the Doppler tones to a harsh, churning, "mill-wheel" quality. Over the next 60 seconds the end-tidal CO2 falls from 34 to 21 mmHg, the blood pressure drops to 78/44 mmHg, and the SpO2 begins to decline. The patient is receiving an oxygen/air/sevoflurane mixture. In addition to alerting the surgeon to flood the field with saline and apply bone wax, which intervention is the MOST appropriate IMMEDIATE next step?', '[{"text":"Increase the inspired sevoflurane concentration to deepen anesthesia and blunt the sympathetic response","label":"A","correct":false,"rationale":"Deepening a volatile anesthetic worsens vasodilation and myocardial depression in an already hypotensive patient and does nothing to address entrained air, so it is harmful here."},{"text":"Apply 10 cm H2O of PEEP to raise intrathoracic pressure and tamponade the venous sinuses","label":"B","correct":false,"rationale":"PEEP is unreliable for preventing air entrainment and can paradoxically promote paradoxical embolism by raising right-atrial pressure above left, so it is not the immediate maneuver of choice."},{"text":"Give a 1 mg/kg bolus of intravenous lidocaine to suppress the ventricular ectopy of air embolism","label":"C","correct":false,"rationale":"Lidocaine treats arrhythmias but does nothing to remove the air or support the failing right heart, and ectopy is not the proximate threat in this scenario."},{"text":"Administer 100% oxygen and attempt to aspirate air from the right-atrial central venous catheter","label":"D","correct":true,"rationale":"Switching to 100% oxygen maximizes oxygenation while eliminating any potential for diffusion-mediated bubble expansion, and aspirating from a correctly positioned right-atrial catheter can directly remove entrained air, making this the correct immediate priority."},{"text":"Place the patient immediately in the Trendelenburg, right-lateral decubitus (Durant) position before any other action","label":"E","correct":false,"rationale":"The Durant position is a classic adjunct but is impractical and slow to achieve in a pinned, sitting craniotomy patient and should not precede giving 100% oxygen and aspirating the catheter."}]'::jsonb, 'D', 'A sudden mill-wheel murmur on precordial Doppler with an abrupt drop in end-tidal CO2 and hypotension is the classic presentation of venous air embolism (VAE), a hallmark risk of sitting-position posterior fossa surgery because the non-collapsible dural venous sinuses sit above the heart. The end-tidal CO2 falls because entrained air increases alveolar dead space and impairs ventilation-perfusion matching. Immediate management is to stop further entrainment (flood the field, wax bone edges, lower the head if feasible), switch to 100% oxygen, discontinue any nitrous oxide, and aspirate air from a right-atrial catheter while providing hemodynamic support. Adjuncts such as the Durant position are secondary and often impractical in a pinned patient.', '{}'::jsonb, 'Subspecialty Care', 'Venous air embolism and sitting-position neurosurgery monitoring', 'hard', '[{"url":"https://www.openanesthesia.org/keywords/venous-air-embolism/","source":"Venous Air Embolism - OpenAnesthesia"}]'::jsonb, 'sme_review', 'Neuro');
